/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications. Currently only
 * email is supported as a notification channel; the model is designed
 * so future channels can be added without breaking existing preferences.
 *
 * Design decisions:
 * - Opt-out model: users receive all notifications by default.
 * - Categories map to the prefix of NotificationType (e.g., 'order', 'user').
 * - Frequency controls batching: 'immediate' sends right away, 'daily-digest'
 *   batches, 'none' suppresses email entirely.
 */

import type { NotificationType } from './notification.js';

/**
 * High-level notification categories derived from NotificationType prefixes.
 * 'order' covers order:confirmation and order:status-update.
 * 'user' covers user:welcome and user:profile-updated.
 */
export type NotificationCategory = 'order' | 'user';

/**
 * Email delivery frequency.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary (future implementation)
 * - 'none': do not send email notifications
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'none';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Global email on/off switch. When false, no emails are sent. */
  enabled: boolean;
  /** How often to deliver email notifications. */
  frequency: EmailFrequency;
  /** Per-category opt-in/out. True means subscribed. */
  categories: Record<NotificationCategory, boolean>;
}

/**
 * Complete notification preferences for a user.
 * One preferences record per user (1:1 relationship).
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  updatedAt: Date;
}

/**
 * Input for updating a user's notification preferences.
 * All fields are optional — only provided fields are updated.
 */
export interface UpdatePreferencesInput {
  email?: {
    enabled?: boolean;
    frequency?: EmailFrequency;
    categories?: Partial<Record<NotificationCategory, boolean>>;
  };
}

/**
 * Default email preferences for new users (opt-out model: everything enabled).
 */
export const defaultEmailPreferences: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  categories: {
    order: true,
    user: true,
  },
};

/**
 * Extract the notification category from a NotificationType.
 * e.g., 'order:confirmation' → 'order', 'user:welcome' → 'user'
 */
export function getCategoryFromType(type: NotificationType): NotificationCategory {
  return type.split(':')[0] as NotificationCategory;
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Each user has at most one preferences record (1:1 relationship).
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, EmailPreferences, NotificationCategory } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user-preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    const categories = JSON.parse(record['emailCategories'] as string) as Record<NotificationCategory, boolean>;

    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailPreferences['frequency'],
        categories,
      },
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailCategories: JSON.stringify(entity.email.categories),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for managing user notification preferences.
 *
 * Depends on:
 * - PreferencesRepository for persistence
 * - UserRepository for validating that the user exists
 *
 * Design:
 * - Opt-out model: if no preferences record exists, the user gets all notifications.
 * - Preferences are created lazily via getOrCreatePreferences().
 * - shouldSendEmail() is the main query used by NotificationService to decide
 *   whether to deliver an email for a given notification type.
 */

import type { NotificationType } from '../models/notification.js';
import type {
  UserPreferences,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import {
  defaultEmailPreferences,
  getCategoryFromType,
} from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Useful for testing. */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private preferencesRepository: PreferencesRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get preferences for a user. Returns undefined if no preferences have
   * been set (caller should treat this as "use defaults").
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating default preferences if none exist.
   * Validates that the user exists before creating.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: { ...defaultEmailPreferences, categories: { ...defaultEmailPreferences.categories } },
      updatedAt: new Date(),
    };

    this.preferencesRepository.save(prefs);
    this.logger.info(`Created default preferences for user ${userId}`);
    return prefs;
  }

  /**
   * Update a user's notification preferences.
   * Creates default preferences first if none exist, then applies updates.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
    const current = this.getOrCreatePreferences(userId);

    const updatedEmail = { ...current.email };
    if (input.email) {
      if (input.email.enabled !== undefined) {
        updatedEmail.enabled = input.email.enabled;
      }
      if (input.email.frequency !== undefined) {
        updatedEmail.frequency = input.email.frequency;
      }
      if (input.email.categories) {
        updatedEmail.categories = {
          ...updatedEmail.categories,
          ...input.email.categories,
        };
      }
    }

    const updated = this.preferencesRepository.update(current.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated preferences for user ${userId}`);
    return updated;
  }

  /**
   * Check whether an email notification should be sent for a given user
   * and notification type, based on the user's preferences.
   *
   * Returns true if:
   * - The user has no preferences (opt-out model: send by default)
   * - Email is globally enabled AND the notification's category is enabled
   *   AND frequency is not 'none'
   */
  shouldSendEmail(userId: string, type: NotificationType): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences = send by default (opt-out model)
    if (!prefs) {
      return true;
    }

    // Global email kill switch
    if (!prefs.email.enabled) {
      return false;
    }

    // Frequency 'none' suppresses all emails
    if (prefs.email.frequency === 'none') {
      return false;
    }

    // Check category-level opt-out
    const category = getCategoryFromType(type);
    return prefs.email.categories[category] !== false;
  }
}

