/**
 * Send a notification: check user preferences, dispatch to the appropriate
 * adapter, and record it.
 *
 * If a PreferencesService is registered, the user's preferences are checked
 * before sending. Suppressed notifications are logged but not recorded or
 * dispatched. If no PreferencesService is set, all notifications are sent
 * (backwards compatible).
 */
private async sendNotification(payload: NotificationPayload): Promise<void> {
  // Check user preferences if a preferences service is available
  if (this.preferencesService && payload.channel === 'email') {
    if (!this.preferencesService.shouldSendEmail(payload.recipient, payload.type)) {
      this.logger.info(
        `Notification suppressed by user preferences: ${payload.type} to ${payload.recipient}`,
      );
      return;
    }
  }

  const record: NotificationRecord = {
    id: generateNotificationId(),
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    channel: payload.channel,
    type: payload.type,
    sentAt: new Date(),
    metadata: payload.metadata,
  };
  this.notifications.push(record);

  const adapter = this.adapters.get(payload.channel);
  if (adapter) {
    try {
      await adapter.send(payload);
    } catch (error) {
      this.logger.error(
        `Adapter failed for channel ${payload.channel}: ${error instanceof Error ? error.message : String(error)}`,
      );
    }
  } else {
    this.logger.warn(`No adapter registered for channel: ${payload.channel}`);
  }

  this.logger.info(`Notification sent: ${record.id} to ${payload.recipient}`);
}

