import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { User } from '../../src/models/user.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

function createTestUser(db: Database, overrides: Partial<User> = {}): User {
  const user: User = {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
  const userRepo = new UserRepository(db);
  userRepo.save(user);
  return user;
}

describe('PreferencesService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let prefsRepo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    prefsRepo = new PreferencesRepository(db);
    service = new PreferencesService(prefsRepo, userRepo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return undefined when no preferences exist', () => {
      expect(service.getPreferences('user-0001')).toBeUndefined();
    });

    it('should return preferences after they are created', () => {
      createTestUser(db);
      service.getOrCreatePreferences('user-0001');

      const prefs = service.getPreferences('user-0001');
      expect(prefs).toBeDefined();
      expect(prefs?.userId).toBe('user-0001');
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should create default preferences for a user', () => {
      createTestUser(db);
      const prefs = service.getOrCreatePreferences('user-0001');

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categories.order).toBe(true);
      expect(prefs.email.categories.user).toBe(true);
    });

    it('should return existing preferences without creating duplicates', () => {
      createTestUser(db);
      const first = service.getOrCreatePreferences('user-0001');
      const second = service.getOrCreatePreferences('user-0001');

      expect(first.id).toBe(second.id);
      expect(prefsRepo.count()).toBe(1);
    });

    it('should throw if user does not exist', () => {
      expect(() => service.getOrCreatePreferences('nonexistent')).toThrow(
        'User not found: nonexistent',
      );
    });

    it('should generate sequential IDs', () => {
      createTestUser(db, { id: 'user-0001' });
      createTestUser(db, { id: 'user-0002', email: 'bob@example.com' });

      const prefs1 = service.getOrCreatePreferences('user-0001');
      const prefs2 = service.getOrCreatePreferences('user-0002');

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('updatePreferences', () => {
    it('should disable email globally', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      // Other settings should remain at defaults
      expect(updated.email.frequency).toBe('immediate');
      expect(updated.email.categories.order).toBe(true);
    });

    it('should change email frequency', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        email: { frequency: 'daily-digest' },
      });

      expect(updated.email.frequency).toBe('daily-digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update a single category without affecting others', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        email: { categories: { order: false } },
      });

      expect(updated.email.categories.order).toBe(false);
      expect(updated.email.categories.user).toBe(true);
    });

    it('should apply multiple changes at once', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        email: {
          frequency: 'none',
          categories: { order: false, user: false },
        },
      });

      expect(updated.email.frequency).toBe('none');
      expect(updated.email.categories.order).toBe(false);
      expect(updated.email.categories.user).toBe(false);
    });

    it('should create preferences if none exist before updating', () => {
      createTestUser(db);
      expect(service.getPreferences('user-0001')).toBeUndefined();

      const updated = service.updatePreferences('user-0001', {
        email: { categories: { order: false } },
      });

      expect(updated.email.categories.order).toBe(false);
      expect(updated.email.categories.user).toBe(true); // Default preserved
    });

    it('should throw if user does not exist', () => {
      expect(() =>
        service.updatePreferences('nonexistent', { email: { enabled: false } }),
      ).toThrow('User not found: nonexistent');
    });

    it('should persist changes across lookups', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        email: { enabled: false },
      });

      const retrieved = service.getPreferences('user-0001');
      expect(retrieved?.email.enabled).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (opt-out model)', () => {
      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(true);
    });

    it('should return true with default preferences', () => {
      createTestUser(db);
      service.getOrCreatePreferences('user-0001');

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'order:status-update')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'user:welcome')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'user:profile-updated')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', { email: { enabled: false } });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-0001', 'user:welcome')).toBe(false);
    });

    it('should return false when frequency is none', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', { email: { frequency: 'none' } });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(false);
    });

    it('should return true when frequency is daily-digest', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', { email: { frequency: 'daily-digest' } });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(true);
    });

    it('should return false for a disabled category', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        email: { categories: { order: false } },
      });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-0001', 'order:status-update')).toBe(false);
      // User category should still be enabled
      expect(service.shouldSendEmail('user-0001', 'user:welcome')).toBe(true);
    });

    it('should respect category-level settings independently', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        email: { categories: { user: false } },
      });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'user:welcome')).toBe(false);
      expect(service.shouldSendEmail('user-0001', 'user:profile-updated')).toBe(false);
    });
  });

  describe('NotificationService integration', () => {
    it('should suppress notifications when user has opted out of category', async () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        email: { categories: { order: false } },
      });

      const eventBus = new EventBus();
      const notifService = new NotificationService(eventBus);
      const emailAdapter = new EmailAdapter();
      notifService.registerAdapter(emailAdapter);
      notifService.setPreferencesService(service);
      resetNotificationIdCounter();

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-0001',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Notification should be suppressed
      expect(notifService.getNotificationCount()).toBe(0);
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
    });

    it('should send notifications when user has default preferences', async () => {
      createTestUser(db);
      service.getOrCreatePreferences('user-0001');

      const eventBus = new EventBus();
      const notifService = new NotificationService(eventBus);
      const emailAdapter = new EmailAdapter();
      notifService.registerAdapter(emailAdapter);
      notifService.setPreferencesService(service);
      resetNotificationIdCounter();

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-0001',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(notifService.getNotificationCount()).toBe(1);
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
    });

    it('should suppress all notifications when email is globally disabled', async () => {
      createTestUser(db);
      service.updatePreferences('user-0001', { email: { enabled: false } });

      const eventBus = new EventBus();
      const notifService = new NotificationService(eventBus);
      const emailAdapter = new EmailAdapter();
      notifService.registerAdapter(emailAdapter);
      notifService.setPreferencesService(service);
      resetNotificationIdCounter();

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-0001',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
